# Clear environment
rm(list = ls())
dev.off(dev.list()["RStudioGD"])  # delete all plots

# Load required packages
library(tidyverse)
library(data.table)
library(devtools)
#install_github("tomatoModelling/cumba_R_package",force=T)
library(cumba)
library(readxl)
library(GA)  # Genetic Algorithm package


# Set working directory to the script's location
setwd(dirname(rstudioapi::getActiveDocumentContext()$path))

# --- Load and Prepare Input Data ---
load("tomatoFoggia.rda")
exp_data<-tomatoFoggia


source('..//R//Main.R')

#load parameters
load("cumbaParameters.rda")
cumba_par <- cumbaParameters
#new parameters set
cumba_par$RUE$value<-2.8 #2-3.5
cumba_par$HalfIntGrowth$value<-19 #10-40
cumba_par$HalfIntSenescence$value<-128 #110-140
cumba_par$KcMax$value<-1.15 #1 - 1.2 #0.9-1.25
cumba_par$FruitWaterContentMax$value<-0.92 #0.88-0.98
cumba_par$RootDepthMax$value<-94 #50-90
cumba_par$FloweringLag$value<-30  # =35da osservazione con dati osservati #20-50
cumba_par$CycleLength$value<-1200  #1200-1600  
cumba_par$WaterStressSensitivity$value<-7 #6-10
cumba_par$RootIncrease$value<-0.7 #0.5-1.5
cumba_par$Topt$value<-24 #22-28
cumba_par$k0$value<-4 #2-6
cumba_par$FruitWaterContentDecreaseMax$value<-0.01 #0.0001-0.001
cumba_par$FruitWaterContentInc$value<-0.10 #0.05-0.15


###

#old parameters set
cumba_par$Tcold$value<-5
cumba_par$FIntMax$value<-.92
cumba_par$TransplantingLag$value<-9
cumba_par$InitialInt$value<-.001
cumba_par$RootDepthInitial$value<-5
cumba_par$SoilWaterInitial$value<-100
cumba_par$DepletionFraction$value<-60
cumba_par$FloweringMax$value<-41
cumba_par$FruitWaterContentMin$value<-0.8


# Define parameters in calibration
pars <- c( "KcMax",
"FruitWaterContentMax", "RootDepthMax","FloweringLag", "CycleLength",
"FruitWaterContentDecreaseMax")


# Extract lower and upper bounds
# Plain numeric vectors (exactly like manual c(...))
lowerPar <- vapply(pars, function(p) cumba_par[[p]]$min, numeric(1))
upperPar <- vapply(pars, function(p) cumba_par[[p]]$max, numeric(1))
lowerPar <- unname(lowerPar)
upperPar <- unname(upperPar)

soil<-read_excel("Dataset Carucci et al. new.xlsx", sheet="Soil")
experiments<- unique(soil$ID)



lowerPar<-c(.8, .80,60, 15, 1000,.0005)
upperPar<-c(1.15,0.98,100,50,1600,0.005)



# --- Define Genetic Algorithm Loss Function ---
lossFunctionGA <- function(params, weather) {
  
  
  # Assign parameter values to model
  
  # cumba_par$RUE$value<-params[1]
  # cumba_par$HalfIntGrowth$value<-params[2]
  # cumba_par$HalfIntSenescence$value<-params[3]
  cumba_par$KcMax$value<-params[1]
  cumba_par$FruitWaterContentMax$value<-params[2]
  cumba_par$RootDepthMax$value<-params[3]
  cumba_par$FloweringLag$value<-params[4]
  cumba_par$CycleLength$value<-params[5]  
  # cumba_par$WaterStressSensitivity$value<-params[9]
  # cumba_par$RootIncrease$value<-params[10]
  # cumba_par$Topt$value<-params[11]
  # cumba_par$k0$value<-params[12]
  cumba_par$FruitWaterContentDecreaseMax$value<-params[6]
  #cumba_par$FruitWaterContentInc$value<-params[14]

  source("..//R//Main.R")
  # Run crop simulation
  results <- list()
  iexp<-experiments[[1]]
  for (iexp in experiments) { 
    
    thisExp <- soil %>% 
      filter(ID == iexp)
    thisYear<- exp_data$irrigation %>% 
      filter(ID==iexp) %>% 
      slice_head() %>% 
      pull(YEAR)
    
    # aggiorna FC SOLO per questo esperimento
    cumba_par$FieldCapacity$value <- thisExp$FC / 100
    cumba_par$WiltingPoint$value<-thisExp$WP/100
    
    results[[as.character(iexp)]] <- cumba_experiment(
      exp_data$weather %>% 
        mutate(year=year(Date)) %>% 
        filter(year == thisYear), cumba_par,
      estimateRad = TRUE, estimateET0 = TRUE,
      exp_data$irrigation %>% 
        filter(ID==iexp),
      fullOut = F
    )
  }
  
  
  out_calib<-do.call(rbind, results)
  
  # Join with yield data and filter for last row per experiment
  out_calib <- as.data.frame(out_calib) |> 
    left_join(exp_data$production, by = c("experiment" = "ID")) |>
    group_by(experiment) |>
    slice_tail()
  
  # objective function definition
  # Calculate normalized RMSE and Pearson correlation
  nrmse_yield <- sqrt(mean((out_calib$yield - out_calib$yield_ref)^2)) / 
    mean(out_calib$yield_ref)
  
  nrmse_brix <- sqrt(mean((out_calib$brix - out_calib$brix_ref)^2)) / 
    mean(out_calib$brix_ref)
  
  
  r_yield <- cor(out_calib$yield, out_calib$yield_ref, method = "pearson")
  r_brix <- cor(out_calib$brix, out_calib$brix_ref, method = "pearson")
  
  # Objective function to minimize
  objFun_yield <- (nrmse_yield * 0.5) + ((1 - r_yield) * 0.5)
  objFun_brix <- (nrmse_brix * 0.5) + ((1 - r_brix) * 0.5)
  
  if(!is.na(objFun_brix))
  {
    objFun <- (objFun_yield+objFun_brix)/2
  }
  else
  {
    objFun<-9999
  }
    
  cat(paste0("RMSE yield: ", round(nrmse_yield, 2), "r yield: ", round(r_yield, 2)),"\n")
  cat(paste0("RMSE brix: ", round(nrmse_brix, 2), "r brix: ", round(r_brix, 2)),"\n")
  cat(paste0("objFun: ", round(objFun, 2)),"\n")
  return(objFun)
}

# Run GA Optimization (see ?ga for advanced settings of the genetic algorithm)
ga_result <- ga(
  type = "real-valued",
  fitness = function(params) -lossFunctionGA(params, exp_data$weather),
  lower = lowerPar,
  upper = upperPar,
  optimArgs = list(method = "L-BFGS-B")
)

best_params <- ga_result@solution                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                               